begin;
delete from public.places where source = 'curated';
create temporary table tmp_osm (slug text primary key, kind public.place_kind, lat float8, lng float8, street text, postal_code text, city text, state text, website text, phone text, opening_hours jsonb, tags text[], name_de text, name_pl text, desc_de text, desc_pl text, source_url text);

select slug, kind, 'published', lat, lng, street, postal_code, city, state, website, phone, opening_hours, tags, 'osm'::public.place_source, source_url, now()
from tmp_osm
on conflict (slug) do update set
  kind=excluded.kind, status='published', lat=excluded.lat, lng=excluded.lng,
  street=excluded.street, postal_code=excluded.postal_code, city=excluded.city, state=excluded.state,
  website=excluded.website, phone=excluded.phone, opening_hours=excluded.opening_hours,
  tags=excluded.tags, source=excluded.source, source_url=excluded.source_url, verified_at=now(), updated_at=now();

select p.id, 'de', s.name_de, s.desc_de, '', s.name_de || ' | Alemniam', left(s.desc_de,155)
from tmp_osm s join public.places p on p.slug=s.slug
on conflict (place_id, locale) do update set name=excluded.name, description=excluded.description, seo_title=excluded.seo_title, seo_description=excluded.seo_description;

select p.id, 'pl', s.name_pl, s.desc_pl, '', s.name_pl || ' | Alemniam', left(s.desc_pl,155)
from tmp_osm s join public.places p on p.slug=s.slug
on conflict (place_id, locale) do update set name=excluded.name, description=excluded.description, seo_title=excluded.seo_title, seo_description=excluded.seo_description;

commit;
